        z = Complex(-2, -2)
        XCTAssertEqualWithAccuracy(sqrt(8), z.modulus, accuracy: ACCURACY)
        XCTAssertEqualWithAccuracy(5*PI/4, z.argument, accuracy: ACCURACY)
    }


