        var z = Complex(1, 2)
        XCTAssertEqual(Quadrant.First, z.quadrant)

        z = Complex(-1, 2)
        XCTAssertEqual(Quadrant.Second, z.quadrant)

        z = Complex(-1, -2)
        XCTAssertEqual(Quadrant.Third, z.quadrant)

        z = Complex(1, -2)
        XCTAssertEqual(Quadrant.Fourth, z.quadrant)
    }



